var getOffsetBranch = (startBranch, offset) => {
  const idx = DiZhiArray.indexOf(startBranch);
  if (idx === -1) return "";
  let newIdx = (idx + offset) % 12;
  if (newIdx < 0) newIdx += 12;
  return DiZhiArray[newIdx];
};
